    { name: { en: 'Gruyère', ro: 'branza Gruyère', ru: 'сыр грюйер', es: 'queso Gruyère' }, measure: '25g grated' },
    { name: { en: 'Lemon', ro: 'lamaie', ru: 'лимон', es: 'limon' }, measure: 'Juice of 1' }
