    { name: { en: 'Egg', ro: 'ou', ru: 'яйцо', es: 'huevo' }, measure: '2' },
    { name: { en: 'Dulce de leche', ro: 'dulce de leche', ru: 'дульсе де лече', es: 'dulce de leche' }, measure: 'To taste' }
