    { name: { en: 'Tarragon Leaves', ro: 'frunze de tarhon', ru: 'листья эстрагона', es: 'hojas de estragon' }, measure: '3 chopped' },
    { name: { en: 'Parsley', ro: 'patrunjel', ru: 'петрушка', es: 'perejil' }, measure: '1 tbs chopped' },
    { name: { en: 'Chives', ro: 'arpagic', ru: 'зелёный лук', es: 'cebollino' }, measure: '1 tbs chopped' },
    { name: { en: 'Gruyère', ro: 'branza Gruyère', ru: 'сыр грюйер', es: 'queso Gruyère' }, measure: '4 tbs' }
